import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";const i=JSON.parse(`{"title":"Zu 26.1 Snapshots portieren","description":"Leitfaden für die Portierung auf Snapshots der nächsten Version von Minecraft.","frontmatter":{"title":"Zu 26.1 Snapshots portieren","description":"Leitfaden für die Portierung auf Snapshots der nächsten Version von Minecraft.","authors":["cassiancc"],"files":[]},"headers":[],"relativePath":"de_de/develop/porting/next.md","filePath":"translated/de_de/develop/porting/next.md","lastUpdated":1770561656000}`);var a={name:`de_de/develop/porting/next.md`};function o(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Zu 26.1 Snapshots portieren <a class="header-anchor" href="#h1" aria-label="Permalink to “Zu 26.1 Snapshots portieren”">​</a></h1><p>Die kommende Version 26.1 von Minecraft ist nicht verschleiert, ebenso wie ihre Snapshots. Mit diesem Hintergrund musst du mehr Änderungen als üblich an deinen Buildskripten vornehmen, um die Portierung durchzuführen.</p><div class="info custom-block"><p class="custom-block-title custom-block-title-default">INFO</p><p>Dieses Dokumentation behandelt die Migration von <strong>1.21.11</strong> auf die Snapshots von <strong>26.1</strong>. Wenn du auf die <strong>1.21.11</strong> migrieren möchtest, lies den Artikel über die <a href="./current">Portierung auf 1.21.11</a>.</p></div><p>Beachte, dass du, wenn dein Mod noch die Yarn-Mappings von Fabric verwendet, zunächst <a href="./../migrating-mappings/">deinen Mod auf die offiziellen Mappings von Mojang migrieren musst</a>, bevor du ihn auf die 26.1 portieren kannst.</p><p>Wenn du die IntelliJ IDEA verwendest, musst du sie ebenfalls auf die Version <code>2025.3</code> oder höher aktualisieren, um die vollständige Unterstützung für Java 25 zu erhalten.</p><h2 id="build-script" tabindex="-1">Das Buildskript aktualisieren <a class="header-anchor" href="#build-script" aria-label="Permalink to “Das Buildskript aktualisieren”">​</a></h2><p>Beginne damit, die Dateien <code>gradle/wrapper/gradle-wrapper.properties</code>, <code>gradle.properties</code> und <code>build.gradle</code> deines Mods auf die neuesten Versionen zu aktualisieren.</p><ol><li>Aktualisiere Gradle auf die aktuellste Version, indem du den folgenden Befehl ausführst: <code>./gradlew wrapper --gradle-version latest</code></li><li>Hebe Minecraft, den Fabric Loader, Fabric Loom und die Fabric API an, entweder in der <code>gradle.properties</code> (empfohlen) oder in der <code>build.gradle</code>. Die empfohlenen Versionen der Fabric-Komponenten findest du auf der <a href="https://fabricmc.net/develop/" target="_blank" rel="noreferrer">Fabric Develop-Website</a>. <ul><li>Beachte, dass 26.1-Snapshots keine stabilen Versionen von Minecraft sind und du diese Version daher manuell aus der Dropdown-Liste auswählen musst.</li></ul></li><li>Ändere oben in der <code>build.gradle</code> die Version von Loom, die du verwendest, von <code>id &quot;fabric-loom&quot;</code> zu <code>id &quot;net.fabricmc.fabric-loom&quot;</code>. Wenn du Loom in der <code>settings.gradle</code> spezifizierst, ändere es dort auch.</li><li>Entferne die Zeile <code>mappings</code> von dem Abschnitt dependencies deiner <code>build.gradle</code>.</li><li>Ersetze jegliche Instanzen von <code>modImplementation</code> oder <code>modCompileOnly</code> mit <code>implementation</code> und <code>compileOnly</code>.</li><li>Entferne oder ersetze alle Mods, die für Versionen vor 26.1 erstellt wurden, durch Versionen, die mit diesem Update kompatibel sind. <ul><li>Keine der vorhandenen Mods für Minecraft 1.21.11 oder ältere Versionen funktioniert mit 26.1, auch nicht als reine Kompilierungsabhängigkeit.</li></ul></li><li>Ersetze alle Erwähnungen von <code>remapJar</code> mit <code>jar</code>.</li><li>Aktualisiere Gradle, indem du auf die Schaltfläche zur Aktualisierung in der oberen rechten Ecke von IntelliJ IDEA klickst. Wenn diese Schaltfläche nicht sichtbar ist, kannst du das Leeren der Caches erzwingen, indem du <code>./gradlew --refresh-dependencies</code> ausführst.</li></ol><h2 id="porting-guides" tabindex="-1">Den Code aktualisieren <a class="header-anchor" href="#porting-guides" aria-label="Permalink to “Den Code aktualisieren”">​</a></h2><p>Nachdem das Buildskript auf 26.1 aktualisiert wurde, kannst du nun deinen Mod durchgehen und allen geänderten Code aktualisieren, um ihn mit dem Snapshot kompatibel zu machen.</p><div class="warning custom-block"><p class="custom-block-title">WICHTIG</p><p>Da Minecraft 26.1 noch in der Snapshot Phase ist, fehlt noch eine Dokumentation zu spezifischen Änderungen. Viel Glück, du bist auf dich allein gestellt!</p></div><ul><li>Der <a href="./26.1/fabric-api">Fabric API 26.1 Leitfaden zur Portierung</a> listet die Umbenennungen auf, die in den 26.1 Snapshots an der Fabric API durchgeführt wurden, um sie an die Namen von Mojang anzupassen.</li><li><a href="https://minecraft.wiki/w/Java_Edition_26.1" target="_blank" rel="noreferrer"><em>Java Edition 26.1</em> im Minecraft Wiki</a> ist eine inoffizielle Zusammenfassung der Inhalte des Updates.</li><li><a href="https://github.com/ChampionAsh5357/neoforged-github/blob/update/26.1/primers/26.1/index.md" target="_blank" rel="noreferrer">NeoForge&#39;s <em>Minecraft 1.21.11 -&gt; 26.1 Mod Migration Primer</em></a> deckt die Migration mit Fokus auf Änderungen des Vanilla Code von 1.21.11 auf 26.1 ab. <ul><li>Bitte beachten, dass es sich bei dem verlinkten Artikel um Material von Dritten handelt, das nicht von Fabric gepflegt wird. Es unterliegt dem Urheberrecht von @ChampionAsh5357 und ist lizenziert unter <a href="https://creativecommons.org/licenses/by/4.0/" target="_blank" rel="noreferrer">Creative Commons Attribution 4.0 International</a>.</li></ul></li></ul>`,12)]])}var s=r(a,[[`render`,o]]);export{i as __pageData,s as default};